import type { DialogueEntry } from '../../../../types';
import { CharacterId } from '../../../../characters';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "（看向李杰）你⋯⋯要跟我們一起走嗎？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰沉默地看著眼前這對母子三人。母親膝蓋上的傷口還在滲血，兩個孩子緊緊抓著她的手，眼神中滿是恐懼與不安。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）跟著他們去亡者峽谷？一個受傷的母親，兩個年幼的孩子⋯⋯在這種鬼地方，這只會成為拖累。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他想起剛才在車站內找到的地圖。三條路線清晰地標示著——北邊的「亡者峽谷」、南邊的「迷霧之森」、還有西邊的「銀月湖」。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）我們才剛認識不到幾個小時，說到底只是陌生人。在這種隨時可能喪命的情況下，帶著他們只會讓我自己也陷入危險。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰深吸一口氣，做出了決定。他從口袋裡掏出那張泛黃的地圖，展開給那位母親看。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（平靜地說）這是我在車站裡找到的地圖。沿著鐵軌走確實能到亡者峽谷，但那條路完全暴露在外，沒有任何遮蔽。" },
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "（抬起頭，眼神中閃過一絲希望）那⋯⋯還有別的路嗎？" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（指著地圖）森林裡有一條主要路徑，也通往北方的亡者峽谷。走那條路應該比沿著鐵軌安全一些，至少有樹木遮蔽。" },
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "（感激地點頭）謝謝你⋯⋯真的謝謝你。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（收起地圖）不過我不會跟你們一起走。我有自己的打算。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "母親愣了一下，但很快理解了他的意思。她沒有表現出失望或責怪，只是輕輕點了點頭。" },
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "（輕聲）我明白。謝謝你告訴我們這些⋯⋯已經幫了我們很多了。" },
    { characterId: CharacterId.KobayashiHina, character: "懂事姐姐", dialogue: "（拉著媽媽的手，小聲問）大哥哥不跟我們一起走嗎？" },
    { characterId: CharacterId.KobayashiTomoko, character: "溫柔母親", dialogue: "（溫柔地摸摸女兒的頭）大哥哥有自己的事情要做。我們要自己去找爸爸，對不對？" },
    { characterId: CharacterId.KobayashiHina, character: "懂事姐姐", dialogue: "（點點頭，看向李杰）那⋯⋯大哥哥你要小心喔。" },
    { characterId: CharacterId.KobayashiShota, character: "天真弟弟", dialogue: "（也揮揮手）拜拜，大哥哥。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（微微點頭）你們也是。小心一點。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "母親牽起兩個孩子的手，朝著森林的北方走去。她的背影在紫月的光輝下顯得有些單薄，但依然挺直。兩個小小的身影緊緊跟在她身旁。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很快，他們的身影就消失在森林的黑暗之中。月台上只剩下李杰一個人。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（低聲自語）祝你們好運。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉過身，看向地圖上標示的西方——銀月湖。那是一個聽起來不那麼兇險的地方。至少，比「亡者峽谷」和「迷霧之森」聽起來要好一些。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）獨自一人，行動會更自由。沒有拖累，也不用為別人的安危負責。在這種地方，這才是最理性的選擇。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他握緊手中的鏽劍，沿著月台走向西側的出口。那裡有一條被雜草覆蓋的小徑，隱約能看出曾經有人走過的痕跡。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰踏上小徑，身後「幽冥之都」的荒廢車站漸漸遠去。兩輪紫月依舊懸在天空，將他的影子拉得很長。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "森林裡的空氣冰冷而潮濕，帶著一股腐葉和潮濕泥土的氣味。頭頂茂密的樹冠幾乎遮住了所有光線，只有零星的紫色月光透過縫隙灑下來，在地面上形成斑駁的光影。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小徑彎彎曲曲，時而被倒下的樹幹擋住，時而被蔓生的藤蔓遮蓋。李杰小心翼翼地撥開擋路的枝葉，一步一步向前。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）這條路很久沒人走過了⋯⋯但至少還能辨認出方向。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "森林裡寂靜得可怕。沒有蟲鳴，沒有鳥叫，甚至連風吹樹葉的聲音都顯得空洞而遙遠。只有李杰自己的腳步聲，踩在落葉上發出的「沙沙」聲響。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走了大約一個小時，李杰停下腳步，靠在一棵粗大的樹幹上休息。他的額頭已經滲出汗水，呼吸也變得有些急促。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（喘著氣，低聲）這森林⋯⋯比想像中還要深。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從口袋裡掏出地圖，藉著微弱的月光查看。按照地圖標示，從車站到銀月湖的距離不算太遠，但實際走起來卻比預期困難得多。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）地圖上看起來只是一小段距離，但這些崎嶇的山路⋯⋯恐怕要走上好幾個小時。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他收起地圖，繼續前進。時間一分一秒地流逝，但在這永恆的紫色夜空下，根本無法判斷過了多久。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個小時。三個小時。李杰的雙腿開始感到痠痛，喉嚨也因為乾渴而發緊。他已經記不清自己爬過多少個小坡，繞過多少棵巨樹。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）該不會走錯路了吧⋯⋯不，小徑還在。只要跟著這條路，應該就沒問題⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就在他幾乎要懷疑這條路是否真的通往銀月湖時，前方的樹林突然變得稀疏起來。透過樹幹的縫隙，他看到了一片較為開闊的空地。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "而在那片空地的中央，立著一座木造房屋。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（停下腳步，驚訝）那是⋯⋯房子？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那是一座單層的木屋，結構簡樸卻完整，看起來保養得相當不錯。木板牆面雖然有些斑駁，但沒有腐朽的跡象。屋頂覆蓋著深色的瓦片，窗戶緊閉，門前還有一個小小的木製台階。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）在這種荒涼的森林深處，居然會有這麼完整的房子？這也太奇怪了⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他握緊手中的鏽劍，警戒地靠近那座木屋。每一步都格外小心，生怕驚動什麼不該驚動的東西。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "木屋周圍很安靜。沒有燈光，沒有人聲，看起來像是廢棄已久。但那完好的結構，又讓人懷疑也許還有人居住。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）先看看裡面有什麼⋯⋯說不定能找到一些補給品，或者關於這個地方的線索。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走上木製台階，伸手握住門把。門沒有上鎖。他深吸一口氣，輕輕推開了門。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「吱呀——」" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門軸發出一聲刺耳的摩擦聲。房間內一片黑暗，只有從門口透進來的微弱月光，照亮了地板上的一小片區域。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰剛踏進門檻——" },
    { characterId: CharacterId.SuzukiAsuka, character: "活潑女大生", dialogue: "（尖叫）不要！不要殺我！求求你！求求你不要殺我！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個年輕女孩的聲音突然從黑暗的角落傳來，充滿了恐懼與絕望。她的聲音顫抖著，帶著哭腔。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（愣住，舉起手中的劍）誰？！" },
    { characterId: CharacterId.SuzukiAsuka, character: "活潑女大生", dialogue: "（哭喊）我什麼都沒做！真的什麼都沒做！求求你放過我！我不想死！嗚嗚嗚⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰的眼睛逐漸適應了黑暗。他看到房間的角落裡，一個女孩縮成一團，雙手抱著頭，身體劇烈顫抖。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的衣服沾滿了泥土和樹葉，頭髮凌亂，臉上滿是淚痕。看起來已經驚嚇過度。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（放下劍，皺眉）等等，妳冷靜一點。我不是什麼殺手，也不會殺妳。" },
    { characterId: CharacterId.SuzukiAsuka, character: "活潑女大生", dialogue: "（哭泣聲漸小，顫抖著抬起頭）你⋯⋯你不會殺我？" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（嘆了口氣）不會。我只是路過這裡的旅人。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "女孩緩緩抬起頭，藉著門口透進來的月光，終於看清了李杰的臉。她的眼睛瞬間睜大。" },
    { characterId: CharacterId.SuzukiAsuka, character: "活潑女大生", dialogue: "（驚訝）你⋯⋯你是⋯⋯列車上的那個人？" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（也認出了她）妳是⋯⋯那群大學生裡的？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒錯。眼前這個驚恐的女孩，正是在「寂海」站第一批下車的那四個年輕人之一——那個在月台上還笑得很開心的活潑女大生。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（放下劍，語氣放緩）冷靜一點。我叫李杰。妳不用怕，我不會傷害妳。" },
    { characterId: CharacterId.SuzukiAsuka, character: "活潑女大生", dialogue: "（擦了擦眼淚，聲音還在顫抖）我⋯⋯我叫鈴木明日香⋯⋯" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（點點頭）明日香，妳為什麼會在這裡？其他人呢？" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一聽到這個問題，明日香的臉色瞬間變得慘白。她的身體又開始劇烈顫抖，眼淚再次奪眶而出。" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（哽咽）我⋯⋯我不知道⋯⋯我不知道他們在哪裡⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她抱著自己的膝蓋，整個人縮得更緊。恐懼再次籠罩了她。" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（顫抖著說）我們⋯⋯我們四個人下車後，看到車站旁邊有兩條路。一條是寬闊的主要道路，另一條是隱密的小路，藏在樹叢後面⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（繼續）健太說主要道路太無聊了，那條隱密的小路看起來更刺激，說不定會有什麼特別的發現⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（苦笑，眼淚流下）我們那時候還覺得⋯⋯就像在玩RPG遊戲找隱藏路線一樣⋯⋯所以就跟著健太走進那條小路了⋯⋯" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（皺眉）只有你們四個？" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（搖頭）不是⋯⋯那個沉穩的大叔看到我們偏離主要道路，好像想叫住我們⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（繼續）他在後面喊說那條路看起來很危險，要我們走主要道路比較安全⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（低下頭）但健太說我們年輕人有冒險精神，不想走那種一眼望到底的大路⋯⋯我們就沒聽他的，繼續往隱密的小路走了⋯⋯" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "那大叔呢？" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（回憶著）他好像嘆了口氣⋯⋯然後我聽到他跟另外兩個人說什麼「這些年輕人太衝動了」⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（不確定地）我猜⋯⋯他們三個應該有跟上來。因為我們走了一段路後，偶爾會聽到後面傳來一些聲音⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（聲音顫抖）但距離有點遠，我也不確定是不是他們⋯⋯" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（點頭）然後呢？" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（哭著）一開始還好，那條小路雖然窄，但健太一直說這才叫冒險⋯⋯我們四個人走在一起，還不算太害怕⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（聲音顫抖）可是走著走著，霧開始變濃了⋯⋯越來越濃，濃到我們幾乎看不清彼此⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音越來越小，像是在回憶那段恐怖的經歷。" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（哭腔）走了好久，大家都累了⋯⋯拓海說看到前面小路的盡頭，有一片比較空曠的地方，我們可以在那裡休息一下⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（突然提高音量，帶著驚恐）可是我們才剛走出小路，美咲突然尖叫了一聲！" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（皺眉）發生了什麼？" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（聲音因恐懼而顫抖）我⋯⋯我不知道！我只聽到她的尖叫聲，然後健太大喊「快跑」！" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（哭泣）大家都嚇壞了，我根本來不及看發生什麼事，就跟著拼命地跑⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（崩潰地）我只記得健太一直喊快跑快跑，拓海也在喊，然後我就拼命地往前衝⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她抱著頭，整個人蜷縮在角落，像一隻受驚的小動物。" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（哭泣）我也不知道自己跑了多久⋯⋯等我停下來的時候，發現周圍一個人都沒有了⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（聲音顫抖）我想回去找美咲，但霧太濃了⋯⋯我根本認不出路⋯⋯走過的地方全都一樣⋯⋯" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（擦著眼淚）我在霧裡走了好幾個小時，完全迷路了⋯⋯最後看到這座房子，就躲進來了⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說完後，整個人癱軟在地上，只剩下抽泣的聲音。經歷了那場恐怖的襲擊，又在霧中迷失了好幾個小時，她已經接近崩潰的邊緣。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（沉默片刻）⋯⋯妳的同伴們，現在不知道在哪裡？" },
    { characterId: CharacterId.SuzukiAsuka, character: "鈴木明日香", dialogue: "（點頭，哽咽）我不知道⋯⋯我真的不知道⋯⋯美咲她⋯⋯她還活著嗎⋯⋯" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰看著眼前這個驚魂未定的女孩。她蜷縮在角落，像一片隨時會被風吹走的落葉。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "而在這座陌生的木屋裡，兩個陌生人因為命運的安排再次相遇。窗外，紫色的月光透過縫隙灑進來，照亮了這間充滿不安的房間。" },
];
